CREATE OR REPLACE FUNCTION fpa_get_docno_changed_shr (as_memno char) RETURNS varchar AS $body$
DECLARE

  ls_docno char(15);

BEGIN
  select sc_mem_m_chang_request.document_no into STRICT ls_docno
  from sc_mem_m_chg_share_det,
    sc_mem_m_chang_request
  where (sc_mem_m_chang_request.document_no = sc_mem_m_chg_share_det.document_no)
  and (sc_mem_m_chang_request.approve_status = '1')
  and (sc_mem_m_chang_request.membership_no = as_memno)
  and (sc_mem_m_chang_request.document_no = (
      SELECT max(xxx.document_no)
      from sc_mem_m_chang_request xxx
      where (xxx.membership_no = sc_mem_m_chang_request.membership_no)
      )) 
;

  return coalesce(ls_docno,' ');
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
